const topics = [
  { topic: 'طلاق توافقی چیست و چه مراحلی دارد؟ بررسی کامل شرایط و مدارک', keyword: 'طلاق توافقی', category: 'حقوق خانواده', img: 'divorce couple separation', word_count: 2000 },
  { topic: 'مهریه چیست؟ انواع مهریه و نحوه مطالبه مهریه از طریق دادگاه', keyword: 'مطالبه مهریه', category: 'حقوق خانواده', img: 'wedding ring gold marriage', word_count: 2000 },
  { topic: 'حضانت فرزند بعد از طلاق: حق حضانت مادر و پدر و سن حضانت', keyword: 'حضانت فرزند', category: 'حقوق خانواده', img: 'child family custody parent', word_count: 1800 },
  { topic: 'نفقه زن: میزان نفقه و شرایط مطالبه نفقه و ضمانت اجرا', keyword: 'نفقه زن', category: 'حقوق خانواده', img: 'family support money finance', word_count: 1500 },
  { topic: 'نحوه طرح شکایت کیفری: مراحل شکایت در دادسرا و مدارک لازم', keyword: 'شکایت کیفری', category: 'حقوق کیفری', img: 'court justice gavel law', word_count: 1800 },
  { topic: 'جرم کلاهبرداری در قانون ایران: تعریف و مصادیق و مجازات', keyword: 'کلاهبرداری', category: 'حقوق کیفری', img: 'fraud scam crime money', word_count: 2000 },
  { topic: 'خیانت در امانت: تعریف حقوقی و تفاوت با سرقت و مجازات', keyword: 'خیانت در امانت', category: 'حقوق کیفری', img: 'trust law crime justice', word_count: 1500 },
  { topic: 'دعاوی ملکی: خلع ید و تصرف عدوانی و الزام به تنظیم سند', keyword: 'دعاوی ملکی', category: 'حقوق ملکی', img: 'property house real estate contract', word_count: 2200 },
  { topic: 'قرارداد اجاره: حقوق موجر و مستاجر و فسخ اجاره', keyword: 'حقوق مستاجر', category: 'حقوق ملکی', img: 'rent apartment house key', word_count: 1800 },
  { topic: 'چک برگشتی: نحوه شکایت و مجازات صادرکننده چک بلامحل', keyword: 'چک برگشتی', category: 'حقوق تجاری', img: 'check bank payment money', word_count: 2000 },
  { topic: 'وصول مطالبات: روش‌های حقوقی وصول طلب و توقیف اموال', keyword: 'وصول مطالبات', category: 'حقوق تجاری', img: 'debt collection money finance', word_count: 1500 },
  { topic: 'قانون ارث در ایران: سهم‌الارث و نحوه تقسیم ارث', keyword: 'تقسیم ارث', category: 'حقوق خانواده', img: 'inheritance family legacy document', word_count: 2200 },
  { topic: 'حقوق کارگر و کارفرما: قرارداد کار و اخراج و سنوات', keyword: 'حقوق کارگر', category: 'حقوق کار', img: 'worker employee labor office', word_count: 1800 },
  { topic: 'دیه چیست؟ نحوه محاسبه دیه و نرخ دیه و انواع دیه', keyword: 'محاسبه دیه', category: 'حقوق کیفری', img: 'court justice law scale', word_count: 1500 },
  { topic: 'چرا به وکیل نیاز دارید؟ مزایای وکیل پایه یک دادگستری', keyword: 'وکیل پایه یک دادگستری همدان', category: 'عمومی', img: 'lawyer attorney legal office', word_count: 1500 }
];

const counter = $getWorkflowStaticData('global');
let index = counter.topicIndex || 0;
if (index >= topics.length) index = 0;

// بررسی تکراری نبودن - چک میکنیم آخرین ۵ مقاله چه موضوعاتی بودن
const recentTopics = counter.recentTopics || [];
let attempts = 0;
while (recentTopics.includes(index) && attempts < topics.length) {
  index = (index + 1) % topics.length;
  attempts++;
}
recentTopics.push(index);
if (recentTopics.length > 5) recentTopics.shift();
counter.recentTopics = recentTopics;

const pick = topics[index];
counter.topicIndex = (index + 1) % topics.length;

return [{ json: { topic: pick.topic, keyword: pick.keyword, category: pick.category, img: pick.img, word_count: pick.word_count, current_index: index } }];

const data = $('ارسال به Claude').first().json;
let raw = '';

if (data.content && Array.isArray(data.content)) {
  raw = data.content[0].text;
} else if (data.text) {
  raw = data.text;
} else if (data.error) {
  const errMsg = typeof data.error === 'string' ? data.error : (data.error.message || JSON.stringify(data.error));
  throw new Error('خطای Claude: ' + errMsg);
} else {
  throw new Error('پاسخ نامعتبر - کلیدهای دریافتی: ' + Object.keys(data).join(', '));
}

if (!raw || raw.length < 50) {
  throw new Error('پاسخ خیلی کوتاه یا خالی: ' + raw.substring(0, 200));
}

function getPart(label, next) {
  let s = raw.indexOf('===' + label + '===');
  if (s === -1) return '';
  s += ('===' + label + '===').length;
  let e = next ? raw.indexOf('===' + next + '===') : raw.length;
  if (e === -1) e = raw.length;
  return raw.substring(s, e).trim();
}

const topicData = $('انتخاب موضوع').first().json;

// دو عنوان A/B
let titleA = getPart('TITLE_A', 'TITLE_B') || topicData.topic;
let titleB = getPart('TITLE_B', 'SLUG') || titleA;

// انتخاب تصادفی بین دو عنوان
const useA = Math.random() > 0.5;
let title = useA ? titleA : titleB;
let abVariant = useA ? 'A' : 'B';

let slug = getPart('SLUG', 'CONTENT') || '';
let content = getPart('CONTENT', 'FAQ_SCHEMA');
let faqSchema = getPart('FAQ_SCHEMA', 'KEYWORD') || '';
let keyword = getPart('KEYWORD', 'META') || topicData.keyword;
let meta = getPart('META', null) || title;
let category = topicData.category || '';

if (!content) {
  content = raw;
}

// اضافه کردن FAQ Schema به انتهای محتوا
if (faqSchema) {
  try {
    JSON.parse(faqSchema);
    content += '\n<script type="application/ld+json">' + faqSchema + '</script>';
  } catch(e) {
    // اگه JSON معتبر نبود، اضافه نکن
  }
}

return [{ json: { title, titleA, titleB, abVariant, slug, content, focus_keyword: keyword, meta_description: meta, category } }];

const data = $json;
const photos = data.photos || [];
if (photos.length === 0) {
  throw new Error('تصویری پیدا نشد');
}
// انتخاب تصادفی از ۱۵ عکس اول
const pick = photos[Math.floor(Math.random() * photos.length)];
const imageUrl = pick.src.large2x || pick.src.large || pick.src.original;
const photographer = pick.photographer || '';
return [{ json: { imageUrl, photographer } }];

const postId = $json.id;
const parsedData = $('پردازش پاسخ').item.json;
const imageId = $('آپلود تصویر').item.json.id;
const categoryName = parsedData.category;

// ساخت بدنه درخواست
const body = {
  featured_media: imageId,
  meta: {
    rank_math_focus_keyword: parsedData.focus_keyword,
    rank_math_description: parsedData.meta_description,
    rank_math_title: parsedData.title
  }
};

return [{ json: { postId, body: JSON.stringify(body), categoryName, postUrl: $json.link || ('https://cheraghilaw.ir/?p=' + postId), title: parsedData.title, abVariant: parsedData.abVariant, titleA: parsedData.titleA, titleB: parsedData.titleB } }];

const categories = $json;
const categoryName = $('آماده‌سازی آپدیت').item.json.categoryName;
const postId = $('آماده‌سازی آپدیت').item.json.postId;

let categoryId = null;

if (Array.isArray(categories) && categories.length > 0) {
  categoryId = categories[0].id;
} 

return [{ json: { postId, categoryId, categoryName, needsCreate: !categoryId } }];

const postId = $('بررسی دسته‌بندی').item.json.postId;
let categoryId;

try {
  categoryId = $('ساخت دسته‌بندی').item.json.id;
} catch(e) {
  categoryId = $('بررسی دسته‌بندی').item.json.categoryId;
}

if (!categoryId) {
  return [{ json: { postId, skip: true } }];
}

return [{ json: { postId, categoryId, body: JSON.stringify({ categories: [categoryId] }) } }];
